starterCode.javascript:
import React, { useState, useMemo } from 'react';

function MyComponent({ items, searchQuery }) {
  const [list, setList] = useState([]);

  useEffect(() => {
    const newList = items.filter(item => item.toString().includes(searchQuery.toString()));
    setList(newList);
  }, [items]);

  return (
    <div>
      {list.map(item => 
        <div key={item}>{item}</div>
      )}
    </div>
  );
}

