class MyComponent:
  def __init__(self, items, search_query):
    self.items = items
    self.search_query = search_query
    self.list = []

  def render(self):
    self.list = [item for item in self.items if str(item).includes(str(self.search_query))]
    return [
      div(item) for item in self.list
    ]

